"use client";

import { useState, useEffect, useMemo } from "react";
import ScopeBar from "@/components/scope-bar";
import DataTable from "@/components/data-table";
import { teamListColumns } from "@/lib/columns";
import type { Team, TeamSeasonTotals } from "@/lib/types";
import { useRouter } from "next/navigation";

type TeamRow = Team & TeamSeasonTotals;

export default function TeamsPage() {
  const router = useRouter();
  const [data, setData] = useState<TeamRow[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch("/api/teams")
      .then((r) => r.json())
      .then((rows) => {
        setData(rows);
        setLoading(false);
      });
  }, []);

  const columns = useMemo(() => teamListColumns(), []);

  return (
    <>
      <div className="flex items-center justify-between gap-4 flex-wrap mb-4">
        <h1 className="text-2xl font-bold tracking-tight">
          All Teams
          {!loading && (
            <span className="text-base font-normal text-slate-400 ml-2">
              {data.length} teams
            </span>
          )}
        </h1>
      </div>
      <div className="flex items-center justify-between gap-4 flex-wrap mb-4">
        <ScopeBar />
      </div>
      {loading ? (
        <div className="text-center py-12 text-slate-400">Loading...</div>
      ) : (
        <DataTable
          columns={columns}
          data={data}
          defaultSortKey="ppg"
          onRowClick={(row) => router.push(`/teams/${row.id}`)}
        />
      )}
    </>
  );
}
