"use client";

import { useState, useMemo, useCallback } from "react";

export interface Column<T> {
  key: string;
  label: string;
  group?: string;
  sortable?: boolean;
  getValue: (row: T) => string | number;
  getSortValue?: (row: T) => number | string;
  align?: "left" | "center" | "right";
  render?: (row: T) => React.ReactNode;
}

type SortDir = "asc" | "desc";

export default function DataTable<T>({
  columns,
  data,
  onRowClick,
  defaultSortKey,
  defaultSortDir = "desc",
}: {
  columns: Column<T>[];
  data: T[];
  onRowClick?: (row: T) => void;
  defaultSortKey?: string;
  defaultSortDir?: SortDir;
}) {
  const [sortKey, setSortKey] = useState(defaultSortKey ?? "");
  const [sortDir, setSortDir] = useState<SortDir>(defaultSortDir);

  const handleSort = useCallback(
    (key: string, sortable?: boolean) => {
      if (sortable === false) return;
      if (sortKey === key) {
        setSortDir((d) => (d === "asc" ? "desc" : "asc"));
      } else {
        setSortKey(key);
        setSortDir("desc");
      }
    },
    [sortKey]
  );

  const sorted = useMemo(() => {
    if (!sortKey) return data;
    const col = columns.find((c) => c.key === sortKey);
    if (!col) return data;
    const getter = col.getSortValue ?? col.getValue;
    return [...data].sort((a, b) => {
      const va = getter(a);
      const vb = getter(b);
      if (typeof va === "number" && typeof vb === "number") {
        return sortDir === "asc" ? va - vb : vb - va;
      }
      const sa = String(va);
      const sb = String(vb);
      return sortDir === "asc"
        ? sa.localeCompare(sb)
        : sb.localeCompare(sa);
    });
  }, [data, sortKey, sortDir, columns]);

  // Build column groups
  const groups = useMemo(() => {
    const result: { label: string; span: number }[] = [];
    let current = "";
    let span = 0;
    for (const col of columns) {
      const g = col.group ?? "";
      if (g === current) {
        span++;
      } else {
        if (span > 0) result.push({ label: current, span });
        current = g;
        span = 1;
      }
    }
    if (span > 0) result.push({ label: current, span });
    return result;
  }, [columns]);

  const hasGroups = groups.some((g) => g.label !== "");

  return (
    <div className="overflow-x-auto border border-slate-200 rounded-lg">
      <table className="w-full text-sm">
        <thead>
          {hasGroups && (
            <tr className="bg-slate-800 text-slate-300">
              {groups.map((g, i) => (
                <th
                  key={i}
                  colSpan={g.span}
                  className="px-2 py-1 text-[10px] font-semibold uppercase tracking-wider text-center border-b border-slate-700"
                >
                  {g.label}
                </th>
              ))}
            </tr>
          )}
          <tr className="bg-slate-900 text-slate-200">
            {columns.map((col) => {
              const active = sortKey === col.key;
              const clickable = col.sortable !== false;
              return (
                <th
                  key={col.key}
                  onClick={() => handleSort(col.key, col.sortable)}
                  className={`px-3 py-2 text-[11px] font-semibold uppercase tracking-wide whitespace-nowrap ${
                    col.align === "left" ? "text-left" : "text-center"
                  } ${clickable ? "cursor-pointer select-none hover:bg-slate-800" : ""} ${
                    active ? "bg-slate-800" : ""
                  }`}
                >
                  <span className="inline-flex items-center gap-1">
                    {col.label}
                    {clickable && (
                      <span className="text-[9px] opacity-40">
                        {active
                          ? sortDir === "asc"
                            ? "\u25B2"
                            : "\u25BC"
                          : "\u21C5"}
                      </span>
                    )}
                  </span>
                </th>
              );
            })}
          </tr>
        </thead>
        <tbody>
          {sorted.length === 0 ? (
            <tr>
              <td
                colSpan={columns.length}
                className="px-4 py-12 text-center text-slate-400"
              >
                No data
              </td>
            </tr>
          ) : (
            sorted.map((row, i) => (
              <tr
                key={i}
                onClick={() => onRowClick?.(row)}
                className={`border-b border-slate-100 ${
                  i % 2 === 0 ? "bg-white" : "bg-slate-50/50"
                } ${
                  onRowClick
                    ? "cursor-pointer hover:bg-blue-50/60"
                    : "hover:bg-slate-50"
                }`}
              >
                {columns.map((col) => {
                  const active = sortKey === col.key;
                  return (
                    <td
                      key={col.key}
                      className={`px-3 py-1.5 whitespace-nowrap ${
                        col.align === "left" ? "text-left" : "text-center"
                      } ${active ? "bg-blue-50/40" : ""}`}
                    >
                      {col.render ? col.render(row) : col.getValue(row)}
                    </td>
                  );
                })}
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}
